     1→/**
     2→ * MesoLayer - DNA-like task block visualization
     3→ *
     4→ * Renders task blocks using InstancedMesh for optimal performance.
     5→ * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
     6→ *
     7→ * Features:
     8→ * - InstancedMesh for all task blocks (single draw call)
     9→ * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
    10→ * - Conflict indicators: red border effect on hasConflict tasks
    11→ * - Alternating row backgrounds for readability
    12→ */
    13→
    14→import { useMemo, useRef, useEffect } from 'react';
    15→import { InstancedMesh, Object3D, Color, Matrix4 } from 'three';
    16→import type { TaskRender } from '../../data/types';
    17→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    18→
    19→interface MesoLayerProps {
    20→  tasks: TaskRender[];
    21→  trainCount: number;
    22→  /** Opacity for LOD transitions (0-1). Default: 1 */
    23→  opacity?: number;
    24→}
    25→
    26→// Color palette matching POC reference
    27→const COLORS: Record<string, string> = {
    28→  blue: '#3b82f6',    // maintenance
    29→  orange: '#f59e0b',  // overhaul
    30→  gray: '#9ca3af',    // inspection
    31→};
    32→
    33→const CONFLICT_COLOR = '#ef4444'; // red for conflicts
    34→
    35→// Row background colors (alternating)
    36→const ROW_BG_EVEN = '#ffffff';
    37→const ROW_BG_ODD = '#f8fafc';
    38→
    39→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    40→
    41→// Task block height (with padding)
    42→const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
    43→const TASK_PADDING_Y = 2;
    44→
    45→/**
    46→ * Renders alternating row backgrounds for train rows
    47→ */
    48→function RowBackgrounds({
    49→  trainCount,
    50→  totalDays,
    51→  opacity = 1,
    52→}: {
    53→  trainCount: number;
    54→  totalDays: number;
    55→  opacity?: number;
    56→}) {
    57→  const totalWidth = totalDays * pxPerDay;
    58→
    59→  return (
    60→    <group>
    61→      {Array.from({ length: trainCount }, (_, i) => (
    62→        <mesh
    63→          key={`row-${i}`}
    64→          position={[
    65→            totalWidth / 2, // Center the row
    66→            -i * pxPerTrain - pxPerTrain / 2, // Y position (negative = down)
    67→            -0.1, // Behind tasks
    68→          ]}
    69→        >
    70→          <planeGeometry args={[totalWidth, pxPerTrain]} />
    71→          <meshBasicMaterial
    72→            color={i % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD}
    73→            transparent
    74→            opacity={0.5 * opacity}
    75→          />
    76→        </mesh>
    77→      ))}
    78→    </group>
    79→  );
    80→}
    81→
    82→/**
    83→ * Main task blocks using InstancedMesh
    84→ */
    85→function TaskBlocks({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
    86→  const meshRef = useRef<InstancedMesh>(null);
    87→  const tempObject = useMemo(() => new Object3D(), []);
    88→  const tempMatrix = useMemo(() => new Matrix4(), []);
    89→
    90→  // Update instance matrices and colors when tasks change
    91→  useEffect(() => {
    92→    if (!meshRef.current) return;
    93→
    94→    const mesh = meshRef.current;
    95→
    96→    tasks.forEach((task, i) => {
    97→      // Calculate position and size
    98→      const width = task.duration * pxPerDay;
    99→      const height = TASK_HEIGHT;
   100→      const x = task.startDay * pxPerDay + width / 2; // Center of task
   101→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2; // Negative Y (down)
   102→      const z = task.hasConflict ? 0.1 : 0; // Conflicts slightly forward
   103→
   104→      // Set transform
   105→      tempObject.position.set(x, y, z);
   106→      tempObject.scale.set(width, height, 1);
   107→      tempObject.updateMatrix();
   108→      mesh.setMatrixAt(i, tempObject.matrix);
   109→
   110→      // Set color
   111→      const color = task.hasConflict
   112→        ? new Color(CONFLICT_COLOR)
   113→        : new Color(COLORS[task.color]);
   114→      mesh.setColorAt(i, color);
   115→    });
   116→
   117→    // Mark buffers for update
   118→    mesh.instanceMatrix.needsUpdate = true;
   119→    if (mesh.instanceColor) {
   120→      mesh.instanceColor.needsUpdate = true;
   121→    }
   122→  }, [tasks, tempObject]);
   123→
   124→  if (tasks.length === 0) {
   125→    return null;
   126→  }
   127→
   128→  return (
   129→    <instancedMesh
   130→      ref={meshRef}
   131→      args={[undefined, undefined, tasks.length]}
   132→    >
   133→      {/* Unit plane centered at origin - will be scaled by instance matrix */}
   134→      <planeGeometry args={[1, 1]} />
   135→      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
   136→    </instancedMesh>
   137→  );
   138→}
   139→
   140→/**
   141→ * Conflict glow effect layer
   142→ * Renders a subtle glow behind conflict tasks
   143→ */
   144→function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
   145→  const conflictTasks = useMemo(
   146→    () => tasks.filter((t) => t.hasConflict),
   147→    [tasks]
   148→  );
   149→
   150→  const meshRef = useRef<InstancedMesh>(null);
   151→  const tempObject = useMemo(() => new Object3D(), []);
   152→
   153→  useEffect(() => {
   154→    if (!meshRef.current || conflictTasks.length === 0) return;
   155→
   156→    const mesh = meshRef.current;
   157→
   158→    conflictTasks.forEach((task, i) => {
   159→      const width = task.duration * pxPerDay + 6; // Slightly larger for glow
   160→      const height = TASK_HEIGHT + 6;
   161→      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
   162→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
