   353→    }
   354→    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   355→    const maxTrainIndex = Math.min(trainCount - 1, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   356→    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
   357→  }, [trainCount, viewportBounds]);
   358→
